# Remove fully contained spans: keep only max-length for each overlap region
def remove_nested(spans_list):
    spans_sorted = sorted(spans_list, key=lambda x: (x['span_start'], -(x['span_end']-x['span_start'])))
    result = []
    for sp in spans_sorted:
        contained = False
        for kept in result:
            if kept['span_start'] <= sp['span_start'] and kept['span_end'] >= sp['span_end']:
                contained = True
                break
        if not contained:
            result.append(sp)
    return result

