# Build the citations list with classification and references, mark invalids with 'خطأ'
spans_data = []

# Helper to add a citation
def add_aya(span, sura_name, sura_number, aya_number):
    spans_data.append({
        "span_start": span['span_start'],
        "span_end": span['span_end'],
        "span_text": span['span_text'],
        "citation_type": "Aya",
        "is_valid": False,
        "aya_reference": {
            "sura_name": sura_name,
            "sura_number": sura_number,
            "aya_number": aya_number
        },
        "hadeeth_reference": {},
        "corrected_text": "خطأ",
        "completely_invalid": True
    })

